33	export function quote(
34	  _customer: Customer,
35	  items: Item[],
36	  _options: QuoteOptions = {},
37	): QuoteResult {
38	  const sumOfBasePremiums = items.reduce(
39	    (sum, item) => sum + basePremiumByType[item.type],
40	    0,
41	  );
42	  const isThreeRuneBlock =
43	    items.length === 3 && items.every((item) => item.type === "rune");
44	  const basePremium = isThreeRuneBlock
45	    ? THREE_RUNE_BLOCK_PREMIUM
46	    : sumOfBasePremiums;
47	  const hasNoItems = items.length === 0;
48	  const premium = hasNoItems ? PROCESSING_FEE : 0;
49	  return { basePremium, premium };
50	}
