const countByType = items.reduce<Record<string, number>>((counts, item) => {
  counts[item.type] = (counts[item.type] ?? 0) + 1;
  return counts;
}, {});
const basePremium = Object.entries(countByType).reduce(
  (sum, [type, count]) =>
    sum +
    (count === 3
      ? THREE_RUNE_BLOCK_PREMIUM
      : count * basePremiumByType[type]),
  0,
);
